<template>
  <header class="header">
    <div class="name">
      <h2>Евгений Русецкий</h2>
      <h3>Front-End Developer</h3>
      <img src="../assets/images/foto.jpeg" alt="foto" />
    </div>
    <div class="contacts">
      <div>
        <p>Дата рождения: {{ birthday }}</p>
        <p>
          Полных лет:
          <span id="age">{{ age }}</span>
        </p>
      </div>
      <div>
        <i class="fas fa-envelope"></i>
        <a href="mailto:benichester@gmail.com" target="_blank">benichester@gmail.com</a>
      </div>
      <div>
        <i class="fas fa-phone"></i>
        <a href="tel:+375298568986">+375 (29) 856 89 86</a>
      </div>
    </div>
    <div class="skill-block-left">
      <h3>Навыки:</h3>
      <ul>
        <li v-for="skill in skills" :key="skill">{{ skill }}</li>
      </ul>
    </div>
    <div class="social">
      <a href="https://vk.com/id28469307" class="fab fa-vk" target="_blank"></a>
      <a href="https://www.instagram.com/evgenrusetskiy" class="fab fa-instagram" target="_blank"></a>
      <a href="https://www.linkedin.com/in/evgeniy-rusetskiy-b2073715a/" class="fab fa-linkedin" target="_blank"></a>
    </div>
  </header>
</template>

<script>
export default {
  data() {
    return {
      birthday: "13.08.1988",
      skills: [
        "HTML5",
        "CSS3(Sass)",
        "JavaScript(Jquery)",
        "Angularjs",
        "Bootstrap",
        "Webpack",
        "npm",
        "Git",
        "Wordpress"
      ]
    };
  },
  computed: {
    age: function() {
      var date = new Date(),
        year = date.getFullYear(),
        month = date.getMonth(),
        day = date.getDate();

      function checkYear() {
        if (month > 7 || month === 7 && day >= 13) {
          return 0;
        } else {
          return 1;
        }
      }
      return year - 1988 - checkYear();
    }
  }
};
</script>

<style>
.header {
  position: fixed;
  margin: 0;
  width: 25%;
  height: 100%;
  min-height: 550px;
  background-color: #2a5885;
  color: #fff;
  text-align: center;
}

.header img {
  width: 50%;
  border-radius: 50%;
}

.name h1 {
  font-weight: normal;
  font-size: 2em;
}

.name h3 {
  font-weight: normal;
}

.contacts div {
  margin: 20px auto;
}

.contacts i {
  font-size: 1.3em;
}

.contacts a {
  text-decoration: none;
  color: #fff;
}

.contacts a:hover {
  text-decoration: underline;
}

.skill-block-left {
  display: none;
}

.social {
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
  bottom: 30px;
}

.fa-vk,
.fa-instagram,
.fa-linkedin {
  margin: 10px;
  text-decoration: none;
  color: #fff;
  font-size: 1.5rem;
}

.fa-vk:hover,
.fa-instagram:hover,
.fa-linkedin:hover {
  color: #fff;
  opacity: .5;
}

@keyframes move {
    0% {
        left: -30%;
        opacity: 0;
    }
    100% {
        left: 0;
        opacity: 1;
    }
}
</style>



