<template>
  <div id="app">
    <left-sidebar />
    <main class="content">
      <my-experience />
      <my-education />
      <my-skills />
      <my-information />
      <print-button />
    </main>
    <a href="http://portfolio.rusetski.ru" class="portfolio-button" target="_blank">
      <i class="fas fa-briefcase"></i>
      <div class="hover-text">Смотреть портфолио</div>
    </a>
  </div>
</template>

<script>
import leftSidebar from "./components/sidebar";
import myExperience from "./components/experience";
import myEducation from "./components/education";
import mySkills from "./components/skills";
import myInformation from "./components/information";
import printButton from "./components/printButton";

export default {
  name: "App",
  components: {
    leftSidebar,
    myExperience,
    myEducation,
    mySkills,
    myInformation,
    printButton
  }
};
</script>

<style>
@font-face {
  font-family: "Oswald";
  src: url(assets/fonts/Oswald-Regular.ttf);
}

@font-face {
  font-family: "Oswald-light";
  src: url(assets/fonts/Oswald-Light.ttf);
}

body {
  margin: 0;
  padding: 0;
  font-family: Oswald-light;
}

a {
  color: #000000;
  text-decoration: none;
}

a:hover {
  color: #2a5885;
}

h1 {
  margin-bottom: 0;
}

i {
  padding: 0 10px 0 0;
}

td {
  margin: 0;
  padding: 0 10px;
}

table tr td:nth-child(odd) {
  text-align: right;
}

.content {
  padding: 0 5% 100px 30%;
  box-sizing: border-box;
}

.date {
  margin-left: 5px;
  color: #999;
  font-size: 14px;
}

.conteiner {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  padding-bottom: 50px;
}

.conteiner:last-child {
  justify-content: space-around;
}

.experience,
.education,
.skills,
.additional-information {
  margin: 0 0 50px;
  animation: fadeIn 1s backwards;
}

.experience {
  animation-delay: 0.5s;
}

.education {
  animation-delay: 0.8s;
}

.skills {
  animation-delay: 1.1s;
}

.additional-information {
  animation-delay: 1.4s;
}

.portfolio-button {
  position: fixed;
  z-index: 1;
  top: -100px;
  right: -100px;
  display: block;
  width: 200px;
  height: 200px;
  transform: rotate(45deg);
  color: #fff;
  font-size: 32px;
  background-color: #2a5885;
  box-shadow: inset 0 0 10px #000;
  transition: 0.3s;
}

.portfolio-button:hover {
  background-color: #fff;
}

.portfolio-button .fa-briefcase {
  position: absolute;
  bottom: 20px;
  padding: 0;
  width: 100%;
  text-align: center;
  transform-origin: center;
  animation: rotate 7s infinite
}

.portfolio-button:hover .fa-briefcase {
  color: #2a5885;
  animation: none;
}

.portfolio-button .hover-text {
  position: absolute;
  left: -105%;
  bottom: -30px;
  width: 100%;
  color: #000;
  text-align: center;
  font-size: 22px;
  transition: 0.3s;
}

.portfolio-button:hover .hover-text {
  left: 0;
}

@keyframes rotate {
  0%, 10%, 20%, 100% {transform: scaleX(1)}
  15% {transform: scaleX(-1)}

}

@keyframes fadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@media print {
  .fa-print.fixed-btn,
  .social,
  .skills,
  .portfolio-button {
    display: none;
  }

  .header {
    position: absolute;
    top: 0;
    left: 0;
    width: 23%;
    background: none;
    color: #000000;
    text-align: center;
  }

  .header img {
    width: 70%;
  }

  .name h1 {
    font-size: 1.2em;
  }

  .name h3 {
    margin: 0 0 20px;
    font-size: 1em;
  }

  .skill-block-left {
    margin: 50px 0 0;
    display: block;
    font-weight: normal;
  }

  table {
    width: 100%;
    border: 1px solid #000;
  }

  table,
  td {
    border-top: 1px solid #000;
    border-bottom: 1px solid #000;
    border-collapse: collapse;
  }

  .experience,
  .education,
  .skills,
  .additional-information {
    margin: 0 0 10px;
  }

  h3 {
    margin: 10px 0 0;
  }

  * {
    margin: 0;
    padding: 0;
    font-weight: normal;
  }
}
</style>



