<template>
  <div class="diagram">
    <canvas ref="dial" width="103px" height="103px"></canvas>
    <slot></slot>
    <p>{{ procent }}%</p>
  </div>
</template>

<script>
export default {
  props: ["procent"],
  data() {
    return {
      width: 100,
      lineWidth: 3,
      borderColor: "#e1e5eb",
      color: "#2a5885"
    };
  },
  mounted: function() {
    var context = this.$refs.dial.getContext("2d");
    var radian = (2 * Math.PI * this.procent) / 100;
    context.arc(
      this.width / 2 + this.lineWidth / 2,
      this.width / 2 + this.lineWidth / 2,
      this.width / 2,
      0,
      2 * Math.PI,
      false
    );
    context.lineWidth = this.lineWidth;
    context.strokeStyle = this.borderColor;
    context.stroke();
    context.beginPath();
    context.arc(
      this.width / 2 + this.lineWidth / 2,
      this.width / 2 + this.lineWidth / 2,
      this.width / 2,
      1.5 * Math.PI,
      radian + 1.5 * Math.PI,
      false
    );
    context.strokeStyle = this.color;
    context.stroke();
  }
};
</script>

<style>
.diagram {
  margin: 30px;
  position: relative;
  border-color: #e1e5eb;
  color: #2a5885;
  font-size: 1.25rem;
  display: inline-block;
  text-align: left;
}

.diagram img {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}

.diagram p {
  margin: 0;
  position: absolute;
  top: 100%;
  width: 100%;
  text-align: center;
  color: #000;
}
</style>



