<template>
  <section class="skills">
    <h2>
      <i class="fas fa-tasks"></i>Навыки
    </h2>
    <div class="skills-conteiner">
      <div class="conteiner">
        <skill-diagram procent="80">
          <img src="../assets/images/icon/html5.png" alt="" />
        </skill-diagram>
        <skill-diagram procent="80">
          <img src="../assets/images/icon/css3.png" alt="" />
        </skill-diagram>
        <skill-diagram procent="50">
          <img src="../assets/images/icon/js.png" alt="" />
        </skill-diagram>
      </div>
      <div class="conteiner" v-show="moreSkills">
        <div class="skill-conteiner">
          <img class="skills-icon" src="../assets/images/icon/jquery.png" alt="jquery" />
          <p class="skill-name">jquery</p>
        </div>
        <div class="skill-conteiner">
          <img class="skills-icon" src="../assets/images/icon/Angular.png" alt="Angular" />
          <p class="skill-name">Angularjs</p>
        </div>
        <div class="skill-conteiner">
          <img class="skills-icon" src="../assets/images/icon/Vue.png" alt="Angular" />
          <p class="skill-name">Vue</p>
        </div>
        <div class="skill-conteiner">
          <img class="skills-icon" src="../assets/images/icon/sass.png" alt="sass" />
          <p class="skill-name">Sass</p>
        </div>
        <div class="skill-conteiner">
          <img class="skills-icon" src="../assets/images/icon/bootstrap.png" alt="bootstrap" />
          <p class="skill-name">Bootstrap</p>
        </div>
        <div class="skill-conteiner">
          <img class="skills-icon" src="../assets/images/icon/webpack.png" alt="webpack" />
          <p class="skill-name">webpack</p>
        </div>
        <div class="skill-conteiner">
          <img class="skills-icon" src="../assets/images/icon/npm.png" alt="npm" />
          <p class="skill-name">Node Package Manager</p>
        </div>
        <div class="skill-conteiner">
          <img class="skills-icon" src="../assets/images/icon/wordpress.png" alt="wordpress" />
          <p class="skill-name">Wordpress</p>
        </div>
      </div>
    </div>
    <div class="more-btn-conteiner">
      <a
        href="#"
        class="more-btn"
        @click.prevent="moreSkills = !moreSkills"
      >{{ moreSkills ? 'Скрыть' : 'Смотреть все'}}</a>
    </div>
  </section>
</template>

<script>
import skillDiagram from "./diagram";

export default {
  data() {
    return {
      moreSkills: false
    };
  },
  components: {
    skillDiagram
  }
};
</script>

<style>
.skill-conteiner {
  width: 20%;
  margin-bottom: 50px;
  text-align: center;
}

.skill-name {
  margin: 0;
}

.more-btn-conteiner {
  text-align: center;
}

.skills-icon {
  width: 56px;
  height: 56px;
}
</style>




