<template>
  <section class="experience">
    <h2>
      <i class="fas fa-briefcase"></i>Опыт работы
    </h2>
    <table v-for="work in experience">
      <tr>
        <td>Место работы:</td>
        <td>{{ work.company }}</td>
      </tr>
      <tr>
        <td>Сайт компании:</td>
        <td>
          <a :href="'http://'+ work.site" target="_blank">{{ work.site }}</a>
        </td>
      </tr>
      <tr>
        <td>Период:</td>
        <td>
          c {{ work.from }} - {{ work.to }}
          <!-- <span class="date">{{ time(work.from, work.to) }}</span> -->
        </td>
      </tr>
      <tr>
        <td>Занимаемая должность:</td>
        <td>{{ work.position }}</td>
      </tr>
      <tr>
        <td>Обязанности:</td>
        <td>
          <ul>
            <li v-for="work in work.work">{{ work }}</li>
          </ul>
        </td>
      </tr>
    </table>
  </section>
</template>

<script>
export default {
  data() {
    return {
      experience: [
        {
          company: "Webcat",
          site: "webcat.by",
          from: "04.05.2018",
          to: "17.07.2019",
          position: "Front-end разработчик",
          work: [
            "Верстка сайтов по PSD макетам",
            "Адаптация под мобильные устройства",
            "Посадка на CMS"
          ]
        }
      ]
    };
  },
  methods: {
    time: function(dateFrom, dateTo) {
      let from = dateFrom.split(".");
      let to = dateTo.split(".");
      let year = +to[2] - +from[2] - (+to[1] > +from[1] ? 0 : 1);
      let month = +to[1] - +from[1] - (+to[0] > +from[0] ? 0 : 1);

      function getYearText(year) {
        if (year < 1) {
          return "";
        } else if (year === 1) {
          return `${year} год`;
        } else if (year > 1 && year < 5) {
          return `${year} года`;
        } else if (year > 4) {
          return `${year} лет`;
        }
      }
      function getMonthText(month) {
        if (month < 1) {
          return "";
        } else if (month === 1) {
          return `${month} месяц`;
        } else if (month > 1 && year < 5) {
          return `${month} месяца`;
        } else if (month > 4) {
          return `${month} месяце`;
        }
      }
      return `${getYearText(year)} ${getMonthText(month)}`;
    }
  }
};
</script>



